/**
 * FiscalCalendars Collection
 *
 * Pre-computed fiscal calendar. One row per calendar date, mapping date → fiscal year/period.
 * Bulk-generated by FiscalPeriodResolver.generateCalendar() based on FiscalPeriods config.
 * Indexed on calendarDate for O(1) lookup: instant period resolution from posting date.
 *
 * Purpose: Denormalized lookup table for real-time GL posting period determination.
 * Used by: GLPostings validation, Period Lock checking, Fiscal reporting.
 *
 * @standard IAS-34:2023 (period metadata: quarter, fiscal year, period label)
 * @standard ISO-8601:2019 (calendarDate in RFC 3339, weekNumber per ISO 8601:2019)
 * @standard ISO-4217:2023 (currencyCode inherited from FiscalPeriods)
 * @standard SAF-T:3.0.2 (regulatoryCode for audit file period coding, e.g., P01_2026)
 * @standard XBRL (period context for financial statement generation)
 * @standard GDPR:2016/679 (immutable after generation; generatedFrom traces lineage)
 * @standard SOX:2402 (audit-trail via chainLeafUuid)
 * @invariant One row per calendar day (no gaps, full coverage per FiscalPeriods config)
 * @invariant calendarDate is unique per fiscal config (indexed for instant lookup)
 * @invariant fiscalYear, fiscalPeriod computed from FiscalPeriods.periodType + calendar date
 * @invariant weekNumber, quarterNumber, monthNumber computed per ISO 8601 / fiscal config
 * @invariant regulatoryCode deterministic: P<periodNumber>_<fiscalYear> (SAF-T format)
 * @invariant generatedFrom links to FiscalPeriods record (immutable origin)
 * @invariant Bulk-generated; read-only after creation (amend via FiscalPeriods → regenerate)
 */

import { CollectionConfig } from 'payload'
import { accountingCollectionAccess } from '../../access/auth'

export const FiscalCalendars: CollectionConfig = {
  slug: 'fiscal-calendars',
  admin: {
    useAsTitle: 'calendarDate',
  },
  access: accountingCollectionAccess(),
  fields: [
    {
      name: 'entity',
      type: 'relationship',
      relationTo: 'legal-entities',
      required: true,
      index: true,
      admin: { description: 'Entity this calendar applies to' },
    },
    {
      name: 'calendarDate',
      type: 'date',
      required: true,
      index: true,
      admin: {
        description:
          'Calendar date (RFC 3339, e.g., 2026-05-12). Indexed for O(1) period lookup via FiscalCalendars.query(tenantId, entityId, calendarDate).',
      },
    },
    {
      name: 'fiscalYear',
      type: 'number',
      required: true,
      admin: {
        description:
          'Fiscal year containing this date (e.g., 2026 for calendar year entity, or 2027 for entity with fiscal year start July 1). Computed from FiscalPeriods config.',
      },
    },
    {
      name: 'fiscalPeriod',
      type: 'number',
      required: true,
      admin: {
        description:
          'Period within fiscal year (1-12 for monthly, 1-4 for quarterly, 1-52/53 for weekly/ISO-week, 1-N for custom). Computed from periodType.',
      },
    },
    {
      name: 'periodStartDate',
      type: 'date',
      required: true,
      admin: { description: 'First day of this period' },
    },
    {
      name: 'periodEndDate',
      type: 'date',
      required: true,
      admin: { description: 'Last day of this period' },
    },
    {
      name: 'periodLabel',
      type: 'text',
      required: true,
      admin: {
        description:
          'Human-readable period label (e.g., "May 2026", "Q2 2026", "Week 19 2026"). Localized per FiscalPeriods.localeCode.',
      },
    },
    {
      name: 'weekNumber',
      type: 'number',
      admin: {
        description:
          'ISO 8601 week number (1-53). Week 1 is the first week with a Thursday. Null if periodType not weekly/iso-week.',
      },
    },
    {
      name: 'quarterNumber',
      type: 'number',
      admin: {
        description:
          'Calendar quarter (Q1=1..Q4=4) for this calendar date, independent of fiscal period. Used for IAS 34 interim reporting alignment.',
      },
    },
    {
      name: 'monthNumber',
      type: 'number',
      admin: {
        description:
          'Calendar month (1=January, 12=December). Independent of fiscal period; used for reporting context.',
      },
    },
    {
      name: 'dayOfWeek',
      type: 'select',
      options: [
        { label: 'Monday', value: '1' },
        { label: 'Tuesday', value: '2' },
        { label: 'Wednesday', value: '3' },
        { label: 'Thursday', value: '4' },
        { label: 'Friday', value: '5' },
        { label: 'Saturday', value: '6' },
        { label: 'Sunday', value: '0' },
      ],
      admin: {
        description: 'ISO 8601 day of week (0=Sunday, 1=Monday, ..., 6=Saturday)',
      },
    },
    {
      name: 'isLeapAdjusted',
      type: 'checkbox',
      defaultValue: false,
      admin: {
        description:
          'True if this date is part of a leap year adjustment (e.g., Feb 29 handling). Set per FiscalPeriods.leapYearAdjustment.',
      },
    },
    {
      name: 'regulatoryCode',
      type: 'text',
      required: true,
      admin: {
        description:
          'Regulatory period coding per SAF-T (e.g., P05_2026 for May 2026, or Q2_2026 for Q2). Deterministic from FiscalPeriods.regulatoryFramework + fiscalYear/period.',
      },
    },
    {
      name: 'generatedFrom',
      type: 'relationship',
      relationTo: 'fiscal-periods',
      required: true,
      admin: {
        description:
          'FiscalPeriods record used to generate this calendar. Immutable origin for audit trail and amendment tracking.',
      },
    },
    {
      name: 'chainLeafUuid',
      type: 'text',
      admin: {
        description:
          'Law 60: Chain leaf for this calendar entry. Computed as sha256(JCS-canonical(FiscalCalendar) || generatedFrom.chainLeafUuid). Enables detection of tampering or generation drift.',
      },
    },
    {
      name: 'notes',
      type: 'textarea',
      admin: {
        description: 'Notes on this calendar entry (e.g., holiday adjustments, special closure dates)',
      },
    },
  ],
}
